import{c as t,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse(`{"title":"Ben's Bites — 2026-04-09","description":"","frontmatter":{"title":"Ben's Bites — 2026-04-09","date":"2026-04-09T00:00:00.000Z","source":"Ben's Bites","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-09-bens-bites.md","filePath":"research/ai-news/2026-04/2026-04-09-bens-bites.md","lastUpdated":1779796674000}`),s={name:"research/ai-news/2026-04/2026-04-09-bens-bites.md"};function n(i,e,l,p,u,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="🍔-ben-s-bites-—-2026-04-09" tabindex="-1">🍔 Ben&#39;s Bites — 2026-04-09 <a class="header-anchor" href="#🍔-ben-s-bites-—-2026-04-09" aria-label="Permalink to &quot;🍔 Ben&#39;s Bites — 2026-04-09&quot;">​</a></h1><blockquote><p>Ben Tossell 的 AI 日報，工具圈消息源 來源：<a href="https://www.bensbites.com/feed" target="_blank" rel="noreferrer">Ben&#39;s Bites</a></p></blockquote><hr><h2 id="anthropic-built-a-model-too-risky-to-release" tabindex="-1"><a href="https://www.bensbites.com/p/anthropic-built-a-model-too-risky" target="_blank" rel="noreferrer">Anthropic built a model too risky to release</a> <a class="header-anchor" href="#anthropic-built-a-model-too-risky-to-release" aria-label="Permalink to &quot;[Anthropic built a model too risky to release](https://www.bensbites.com/p/anthropic-built-a-model-too-risky)&quot;">​</a></h2><p><em>🍔 Ben&#39;s Bites | 2026-04-09</em></p><p>Hey folks, Keshav here. Ben is at AI Engineer this week, so I’m covering the intro.</p><p>A mis-timed blog last week leaked Anthropic’s next model - Claude Mythos. Well, it is real and has massive improvements on benchmarks over Opus 4.6:</p><p>53.4% → 77.8% on SWE-bench Pro</p><p>65.4% → 82% on Terminal-Bench 2.0</p><p>but we are not getting access to it anytime soon. Why? because it is really good at finding and exploiting software vulnerabilities. On Firefox exploit generation, Opus managed 2 working exploits out of hundreds of attempts. Mythos hit 181.</p><p>It found many-decades-old bugs in critical software projects like OpenBSD (27-year-old bug), FFmpeg (16-year-old bug) and more.</p><p>Instead of releasing it publicly, Anthropic is giving 12 companies access to a preview version of Mythos under “<a href="https://www.anthropic.com/glasswing" target="_blank" rel="noreferrer">Project Glasswing</a>” to find vulnerabilities in critical software. Anthropic is committing $100M in model usage credits and $4M in donations to open-source security orgs under this project.</p><p>Theo made a <a href="https://www.youtube.com/watch?v=aFcVKzfkJPk" target="_blank" rel="noreferrer">video</a> on this, and I like his point: “Mythos is to Opus what Opus is to Sonnet.”</p><p>I tweeted a <a href="https://x.com/Keshavatearth/status/2041817134708486192" target="_blank" rel="noreferrer">list of companies that Meta has acquired</a> in the past year without anything to show for it, and soon after, Meta released details about their latest model - <a href="https://ai.meta.com/blog/introducing-muse-spark-msl/" target="_blank" rel="noreferrer">Muse Spark</a>. At a glance, it sits somewhere between Sonnet 4.6 and Opus 4.6. Not usable yet: API access is coming, and there are promises about open-source too (rip llama).</p><p>Many people are dunking on Meta for its not-so-frontier model release after spending billions and a year of silence, but I think it’s a good step ahead. Plus, have you used Instagram search over the past couple of months? It’s gotten really good courtesy of AI.</p><p>As always, good recap from Ethan Mollick on the <a href="https://x.com/emollick/status/2042088011748290750" target="_blank" rel="noreferrer">state of frontier models</a>: Google, OpenAI and Anthropic lead, Meta joins the pack for now while xAI has fallen off, and the best Chinese models are still 7-9 months behind.</p><p>ps: <a href="https://x.com/FactoryAI/status/2041928406158471299" target="_blank" rel="noreferrer">Factory’s desktop app</a> is now out of beta. It comes with a cloud computer, the ability to use other apps on your device, and, of course, the ability to run and manage multiple Droid sessions easily.</p><p>Ben’s Bites is brought to you by <a href="https://attio.com/?utm_source=bens_bites&amp;utm_medium=newsletter_sponsorship&amp;utm_campaign=bens_bites-Y26" target="_blank" rel="noreferrer">Attio</a>, the AI CRM</p><p>Honestly, no one gets excited about a CRM. But then they try <a href="https://attio.com/?utm_source=bens_bites&amp;utm_medium=newsletter_sponsorship&amp;utm_campaign=bens_bites-Y26" target="_blank" rel="noreferrer">Attio</a>. It connects to Claude Code and n8n through its MCP server, completely bridging the gap between my customer data and apps. Wait, there&#39;s more, like flagging churn risk and turning customer feedback into Linear projects. <a href="https://attio.com/?utm_source=bens_bites&amp;utm_medium=newsletter_sponsorship&amp;utm_campaign=bens_bites-Y26" target="_blank" rel="noreferrer">Try it now</a>.</p><p>Headlines</p><p><a href="https://x.com/claudeai/status/2041927687460024721" target="_blank" rel="noreferrer">Claude Managed Agents</a> - You can use Claude’s developer console to build and deploy agents and let anthropic handle the infra for it, vs building it yourself. For example, <a href="https://x.com/adamwathan/status/2041977909502489060" target="_blank" rel="noreferrer">Notion</a> is using managed agents to build a “delegate tasks to Claude” feature. (Anthropic’s <a href="https://www.anthropic.com/engineering/managed-agents" target="_blank" rel="noreferrer">engineering blog</a> on building this).</p><p><a href="https://x.com/cursor_ai/status/2041561791243940092" target="_blank" rel="noreferrer">Cursor has a new design mode</a> to annotate and target UI elements in the browser. Plus, run Cursor on any machine and <a href="https://x.com/cursor_ai/status/2041912812637966552" target="_blank" rel="noreferrer">control it from anywhere</a>, including your phone.</p><p><a href="https://blog.google/innovation-and-ai/products/gemini-app/notebooks-gemini-notebooklm/" target="_blank" rel="noreferrer">Gemini app finally has projects - they call it notebooks</a>. Similar features as Claude/ChatGPT projects - move chats in/out of notebooks, notebook-specific files and memories, with the additional feature to sync these notebooks between the Gemini app and NotebookLM.</p><p><a href="https://www.clicky.so/" target="_blank" rel="noreferrer">Clicky is an ambient AI buddy on your Mac</a>. It sees your screen, talks to you and points at things to guide you (<a href="https://x.com/FarzaTV/status/2041314633978659092" target="_blank" rel="noreferrer">demo</a>). Farza built (and <a href="https://github.com/farzaa/clicky" target="_blank" rel="noreferrer">open-sourced</a>) it as a learning tool, but people are using it for <a href="https://x.com/FarzaTV/status/2041639363457773867" target="_blank" rel="noreferrer">everything</a>.</p><p>Choosing an accurate speech-to-text model is harder than it looks. Benchmarking one is even harder. See why standard word error rate falls short, and <a href="https://www.assemblyai.com/blog/new-word-error-rate-wer-benchmark?utm_source=bensbites&amp;utm_medium=newsletter_sponsor&amp;utm_campaign=toptools&amp;utm_content=wer_chart_truthfiles" target="_blank" rel="noreferrer">what better STT evaluation actually looks like</a>.*</p><p>My feed</p><p><a href="https://chr.so/notes-to-decks" target="_blank" rel="noreferrer">Chronicle</a>: Cursor for slides. Never build a deck from scratch again. Turn ideas into stunning presentations in minutes.*</p><p><a href="https://x.com/alexatallah/status/2041627373695856776" target="_blank" rel="noreferrer">OpenRouter Spawn</a> - Deploy OpenClaw and other agents to the cloud of your choice. Works with all models on OpenRouter.</p><p><a href="https://x.com/wadefoster/status/2041501747105890393" target="_blank" rel="noreferrer">Zapier’s SDK is now open to everyone</a>. Programmatic access to all of Zapier’s capabilities. Free to use in beta. (<a href="https://docs.zapier.com/sdk/quickstart" target="_blank" rel="noreferrer">docs</a>)</p><p><a href="https://kiro.dev/" target="_blank" rel="noreferrer">Kiro.dev</a> (spec-driven IDE from Amazon) is bringing its <a href="https://kiro.dev/blog/bringing-back-startup-credits/" target="_blank" rel="noreferrer">startup credits program</a> back for startups with up to 30 people.</p><p><a href="https://x.com/linuz90/status/2041867942489669722" target="_blank" rel="noreferrer">Cogito</a> - Markdown editor for Mac. I’ve been using Clearly ([recently updated](<a href="http://Cogito" target="_blank" rel="noreferrer">http://Cogito</a> - Markdown editor for Mac)) for the last few weeks to simply view and edit md files.</p><p><a href="https://github.com/safishamsi/graphify" target="_blank" rel="noreferrer">Graphify</a> - Turn any codebase or folder into a queryable knowledge graph.</p><p><a href="https://mariozechner.at/posts/2026-04-08-ive-sold-out/" target="_blank" rel="noreferrer">Pi and Mario</a> (the maker of Pi) are joining Earendil, the company by the creator of Flask. The core harness stays open-source. New features will be a mix of enterprise &amp; fair source (proprietary now, open-source later).</p><p><a href="https://impeccable.style" target="_blank" rel="noreferrer">Impeccable</a> - Free design skills for coding agents with 21 commands to audit and fix common mistakes.</p><p><a href="https://superset.sh" target="_blank" rel="noreferrer">Superset</a> and <a href="https://x.com/Steve8708/status/2041909436059615442" target="_blank" rel="noreferrer">Builder 2.0</a> - two new UIs for running parallel agents. Superset is more like Codex (terminal-first, worktrees), Builder is more kanban-style with Slack/Jira integration.</p><p><a href="https://x.com/motiondotdev/status/2041513799056826571" target="_blank" rel="noreferrer">CSS Studio</a> by Motion - Make design changes by hand on your website in the browser, then pass them over to your agent for implementation.</p><p><a href="https://aws.amazon.com/about-aws/whats-new/2026/04/amazon-s3-files/" target="_blank" rel="noreferrer">S3 Files from AWS</a> allows storing data as a file system, making it easier for agents to use.</p><p><a href="https://www.youtube.com/watch?v=SRlTgIhESjw" target="_blank" rel="noreferrer">Every is running two parallel org charts</a> - one for humans and another for each employee’s openclaw agents.</p><p>Afters</p><p>ui.sh demo — generating multiple design ideas to choose from, no matter what tech stack you use: &quot;,&quot;username&quot;:&quot;adamwathan&quot;,&quot;name&quot;:&quot;Adam Wathan&quot;,&quot;profile_image_url&quot;:&quot;<a href="https://pbs.substack.com/profile_images/1677042510839857154/Kq4tpySA_normal.jpg%22,%22date%22:%222026-04-08T20:34:06.000Z%22,%22photos%22:%5B%7B%22img_url%22:%22https://substackcdn.com/image/upload/w_1028,c_limit,q_auto:best/l_twitter_play_button_rvaygk,w_88/m4hnc3mskg5xn95rxdd3%22,%22link_url%22:%22https://t.co/Wd0HwBfVVW%22%7D%5D,%22quoted_tweet%22:%7B%7D,%22reply_count%22:139,%22retweet_count%22:112,%22like_count%22:2168,%22impression_count%22:159565,%22expanded_url%22:null,%22video_url%22:%22https://video.twimg.com/amplify_video/2041977682879983616/vid/avc1/1072x720/iw1ZUf9OyAqaffgy.mp4%22,%22belowTheFold%22:true%7D%22" target="_blank" rel="noreferrer">https://pbs.substack.com/profile_images/1677042510839857154/Kq4tpySA_normal.jpg&quot;,&quot;date&quot;:&quot;2026-04-08T20:34:06.000Z&quot;,&quot;photos&quot;:[{&quot;img_url&quot;:&quot;https://substackcdn.com/image/upload/w_1028,c_limit,q_auto:best/l_twitter_play_button_rvaygk,w_88/m4hnc3mskg5xn95rxdd3&quot;,&quot;link_url&quot;:&quot;https://t.co/Wd0HwBfVVW&quot;}],&quot;quoted_tweet&quot;:{},&quot;reply_count&quot;:139,&quot;retweet_count&quot;:112,&quot;like_count&quot;:2168,&quot;impression_count&quot;:159565,&quot;expanded_url&quot;:null,&quot;video_url&quot;:&quot;https://video.twimg.com/amplify_video/2041977682879983616/vid/avc1/1072x720/iw1ZUf9OyAqaffgy.mp4&quot;,&quot;belowTheFold&quot;:true}&quot;</a> data-component-name=&quot;Twitter2ToDOM&quot;&gt;</p><p>Find me on <a href="https://x.com/bentossell/" target="_blank" rel="noreferrer">X</a>, <a href="https://www.linkedin.com/in/ben-tossell-70453537/" target="_blank" rel="noreferrer">Linkedin</a>, or <a href="https://www.youtube.com/@bentossell694" target="_blank" rel="noreferrer">YouTube</a></p><p>Read <a href="https://bensbites.substack.com/about" target="_blank" rel="noreferrer">about me</a> and Ben’s Bites</p><p>📷 thumbnail by <a href="https://www.x.com/keshavatearth" target="_blank" rel="noreferrer">@keshavatearth</a></p><ul><li>sponsors who make this newsletter possible 😃</li></ul><p>Wanna partner with us for the next quarter?</p><p>Email us at <a href="mailto:shanice@bensbites.com" target="_blank" rel="noreferrer">shanice@bensbites.com</a> or <a href="mailto:k@bensbites.com" target="_blank" rel="noreferrer">k@bensbites.com</a></p><hr>',47)])])}const d=t(s,[["render",n]]);export{m as __pageData,d as default};
